code = """import json

# Read the full result from the file
result_file = locals()['var_functions.query_db:6']

# Open and read the file
with open(result_file, 'r') as f:
    businesses = json.load(f)

# Find businesses with WiFi attribute
wifi_businesses = []
for business in businesses:
    if isinstance(business.get('attributes'), dict):
        wifi_value = business['attributes'].get('WiFi')
        if wifi_value:
            wifi_businesses.append(business)

# Extract business IDs and state information
wifi_business_info = []
for business in wifi_businesses:
    business_id = business['business_id']
    wifi_status = business['attributes'].get('WiFi')
    description = business.get('description', '')
    
    # Extract state from description
    state = None
    if 'description' in business:
        desc = business['description']
        # Look for state abbreviation (CA, NY, etc.) - pattern: ', XX, '
        import re
        match = re.search(r',\s*([A-Z]{2})\s*,|\bin\s+([A-Z]{2})\b|,\s*([A-Z]{2})\s+\d+', desc)
        if match:
            state = match.group(1) or match.group(2) or match.group(3)
    
    wifi_business_info.append({
        'business_id': business_id,
        'wifi': wifi_status,
        'state': state
    })

# Show summary
wifi_states = {}
for business in wifi_business_info:
    state = business['state']
    if state:
        wifi_states[state] = wifi_states.get(state, 0) + 1

# Sort by count
sorted_states = sorted(wifi_states.items(), key=lambda x: x[1], reverse=True)

print("__RESULT__:")
print(json.dumps({
    'total_wifi_businesses': len(wifi_business_info),
    'top_states': sorted_states[:10],
    'business_list': wifi_business_info[:20]
}))"""

